function computeTrustScore(address: string, context: string): number {
  const kept   = commitments.filter(c => c.status === 'kept').length;
  const broken = commitments.filter(c => c.status === 'broken').length;
  const ratio  = kept / (kept + broken) || 0.5;

  const vouchW = vouches.reduce((s, v) =>
    s + computeTrustScore(v.voucher, context) * v.weight, 0);

  const tenure = Math.min(Math.log(daysActive + 1) / Math.log(365), 1.0);

  return 0.40 * ratio + 0.35 * Math.min(vouchW/5, 1) + 0.25 * tenure;
}
