async function establishSession(theirPublicKey) {
  const myPrivKey = secp256k1.utils.randomPrivateKey();
  const shared    = secp256k1.getSharedSecret(myPrivKey, theirPublicKey);
  const aesKey    = hkdf(sha256, shared.slice(1,33), undefined, 'P2PAIR-v1', 32);
  return { aesKey, myPubKey: secp256k1.getPublicKey(myPrivKey) };
}
